  const cbBody = JSON.stringify({
    event: 'final_review_complete',
    project_id: projectId,
    data: { quality: review.final_quality, summary: review.summary, suggestions: review.suggestions }
  });
  const req = http.request({
    hostname: 'forge', port: 3500, path: '/api/status-callback',
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) }
  });
  req.on('error', () => {});
  req.write(cbBody);
  req.end();
} catch(e) {}

return [{ json: review }];

const http = require('http');
function lmsRequest(method, path, body) {
  return new Promise((resolve, reject) => {
    const lmsHost = ($env.LM_STUDIO_HOST || 'http://10.0.0.100:1234').replace(/^https?:\/\//, '');
    const [hostname, portStr] = lmsHost.split(':');
    const bodyStr = body ? JSON.stringify(body) : null;
    const req = http.request({
      hostname, port: parseInt(portStr) || 1234, path, method,
      headers: {
        Authorization: 'Bearer ' + ($env.LLM_API_KEY || ''),
        'Content-Type': 'application/json',
        ...(bodyStr ? { 'Content-Length': Buffer.byteLength(bodyStr) } : {})
      }
    }, res => {
      let d = ''; res.on('data', c => d += c);
      res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve({}); } });
    });
    req.on('error', reject);
    if (bodyStr) req.write(bodyStr);
    req.end();
  });
}
const modelKey = $env.PLANNER_MODEL || '';
try {
  const resp = await lmsRequest('GET', '/api/v1/models');
  for (const m of (resp.models || [])) {
    if (m.key === modelKey) {
      for (const inst of (m.loaded_instances || [])) {
        try { await lmsRequest('POST', '/api/v1/models/unload', { instance_id: inst.id }); } catch(e) {}
      }
    }
  }
} catch(e) {}
return [{ json: $('Final: Review Parse').first().json }];

