import './index.css';
import { useGameLogic } from './hooks/useGameLogic';
import CookieButton from './components/CookieButton';
import FloatingNumber from './components/FloatingNumber';
import GameHeader from './components/GameHeader';
import GameFooter from './components/GameFooter';

function App() {
  const {
    score,
    buildings,
    elapsedSeconds,
    buyBuilding,
    handleClick,
    floatingNumbers,
    cookiesPerSecond,
    spawnFloatingNumber
  } = useGameLogic();

  return (
    <div className="app-container">
      <GameHeader score={score} CPS={cookiesPerSecond} />
      <main className="center-content">
        <CookieButton onCookieClick={(x, y, val) => { handleClick(); spawnFloatingNumber(x, y, val); }} />
        {floatingNumbers.map((number) => (
          <FloatingNumber
            key={number.id}
            x={number.x}
            y={number.y}
            value={number.value}
          />
        ))}
      </main>
      <GameFooter 
        elapsedSeconds={elapsedSeconds} 
        buildings={buildings} 
        buyBuilding={buyBuilding} 
      />
    </div>
  );
}

export default App;

import React from 'react';

const CookieButton = ({ onCookieClick }) => {
  const handleClick = (e) => {
    // Capture mouse coordinates and pass them along with click value
    const x = e.clientX;
    const y = e.clientY;
    const clickValue = 1; // Default click value

    // Pass coordinates and click value to parent function
    onCookieClick(x, y, clickValue);
  };

  return (
    <div className="cookie-container">
      <button 
        className="cookie-button"
        onClick={handleClick}
        aria-label="Cookie button"
      >
        {/* Cookie image with emoji */}
        <div className="cookie-image">🍪</div>
      </button>
    </div>
  );
};

export default CookieButton;

import React from 'react';

const FloatingNumber = ({ x, y, value }) => {
  return (
    <div
      className="floating-number"
      style={{
        position: 'absolute',
        left: `${x}px`,
        top: `${y}px`,
        transform: 'translate(-50%, -50%)',
        fontSize: '1.2rem',
        fontWeight: 'bold',
        color: '#333',
        pointerEvents: 'none',
        animation: 'floatUp 1s ease-out forwards',
      }}
    >
      +{value}
    </div>
  );
};

export default FloatingNumber;

import React from 'react';
import { formatTime } from '../utils/formatNumber';

const GameFooter = ({ elapsedSeconds, buildings, buyBuilding, score }) => {
  const nextRankTarget = 100;
  const progressPercent = nextRankTarget > 0 ? (score / nextRankTarget) * 100 : 0;

  return (
    <div className="game-footer">
      <div className="progress-bar-container">
        <div 
          className="progress-bar" 
          style={{ width: `${Math.min(progressPercent, 100)}%` }}
        />
      </div>
      <div className="timer">{formatTime(elapsedSeconds)}</div>
      <div className="shop">
        {buildings.map((building) => (
          <button 
            key={building.id} 
            className="shop-button"
            onClick={() => buyBuilding(building.id)}
          >
            {building.name} - {building.cost} cookies
          </button>
        ))}
      </div>
    </div>
  );
};

export default GameFooter;

import React from 'react';

const GameHeader = ({ score, CPS = 0 }) => {
  return (
    <div className="game-header">
      <h1 style={{ fontSize: '3rem', color: 'white', marginBottom: '8px' }}>
        {score.toLocaleString()}
      </h1>
      <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
        <svg 
          width="20" 
          height="20" 
          viewBox="0 0 24 24" 
          fill="gold"
          xmlns="http://www.w3.org/2000/svg"
        >
          <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-2 15l-5-5 1.41-1.41L10 14.17l7.59-7.59L19 8l-9 9z"/>
        </svg>
        <span style={{ color: 'gold', fontSize: '1rem' }}>
          {CPS.toFixed(1)} CPS
        </span>
      </div>
    </div>
  );
};

export default GameHeader;

import { useState, useEffect } from 'react';
import { formatNumber } from '../utils/formatNumber';

export function useGameLogic() {
  const [totalCookies, setTotalCookies] = useState(0);
  const [cookiesPerSecond, setCookiesPerSecond] = useState(0);
  const [clickValue, setClickValue] = useState(1);
  const [floatingNumbers, setFloatingNumbers] = useState([]);

  // Initialize buildings state
  const [buildings, setBuildings] = useState([
    { id: 1, name: 'Cursor', cost: 15, count: 0, cps: 0.1 },
    { id: 2, name: 'Grandma', cost: 100, count: 0, cps: 1 },
    { id: 3, name: 'Farm', cost: 1100, count: 0, cps: 8 },
  ]);

  // Timer feature
  const [elapsedSeconds, setElapsedSeconds] = useState(0);

  useEffect(() => {
    const intervalId = setInterval(() => {
      setElapsedSeconds(prev => prev + 1);
    }, 1000);

    return () => clearInterval(intervalId);
  }, []);

  useEffect(() => {
    const intervalId = setInterval(() => {
      setTotalCookies(prev => prev + cookiesPerSecond);
    }, 1000);

    return () => clearInterval(intervalId);
  }, [cookiesPerSecond]);

  const increment = (amount = 1) => {
    setTotalCookies(prev => prev + amount);
  };

  const handleClick = () => {
    increment(clickValue);
  };

  const buyBuilding = (buildingId) => {
    const building = buildings.find(b => b.id === buildingId);

    if (!building || totalCookies < building.cost) return;

    // Deduct cost from score
    setTotalCookies(prev => prev - building.cost);

    // Update building count
    setBuildings(prevBuildings =>
      prevBuildings.map(b =>
        b.id === buildingId
          ? { ...b, count: b.count + 1, cost: Math.floor(b.cost * 1.15) }
          : b
      )
    );

    // Update cookies per second
    setCookiesPerSecond(prev => prev + building.cps);
  };

  const spawnFloatingNumber = (x, y, value) => {
    const newNumber = {
      id: Date.now(),
      value,
      x,
      y,
    };

    setFloatingNumbers(prev => [...prev, newNumber]);

    // Remove after animation completes
    setTimeout(() => {
      setFloatingNumbers(prev => prev.filter(num => num.id !== newNumber.id));
    }, 1000);
  };

  return {
    score: totalCookies,
    buildings,
    buyBuilding,
    floatingNumbers,
    spawnFloatingNumber,
    handleClick,
    cookiesPerSecond,
    elapsedSeconds
  };
}

