// Startup: Unload all loaded models before beginning pipeline
// Prevents leftover models from crashed/cancelled runs eating VRAM
const http = require('http');

function httpRequest(options, body) {
  return new Promise((resolve, reject) => {
    const req = http.request(options, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(data)); }
        catch(e) { resolve(data); }
      });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

const host = '10.0.0.100';
const port = 1234;
const apiKey = $env.LLM_API_KEY || '';

// Get all loaded instances
const modelsResp = await httpRequest({
  host, port,
  path: '/api/v1/models',
  method: 'GET',
  headers: { 'Authorization': 'Bearer ' + apiKey }
});

const unloaded = [];
for (const model of (modelsResp.models || [])) {
  for (const inst of (model.loaded_instances || [])) {
    const body = JSON.stringify({ instance_id: inst.id });
    await httpRequest({
      host, port,
      path: '/api/v1/models/unload',
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + apiKey,
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body)
      }
    }, body);
    unloaded.push(inst.id);
  }
}

return [{ json: { ...$json, _startupUnloaded: unloaded } }];

// Gate: pass through next item if NOT done, return [] if done
